head.script:
//ds/common/script/dscommon.js cf_gidHourCheck(), cf_gidHourNullCheck() 구현안됨
scwin.sUserClsCd = "";
scwin.sClntNo = "";
scwin.sClntNm = "";
scwin.sLobranCd = "";

scwin.params = "";
scwin.vehclNoCd = "";
scwin.vehclNo = "";
scwin.wrkDt = "";
scwin.odrNo = "";
scwin.wrkLobranCd = "";

scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd"); // 현재년월일을 구한다.
scwin.g_chkScroll = false;
scwin.result = "";
scwin.pos_groupCode = 0;

//hidden
scwin.hid_srchSelfTransCoCd = "";

//hidVal
scwin.txt_srchSelfTransCoNm = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
    let memJson = $c.data.getMemInfo();
    console.log(memJson);

    scwin.sUserClsCd = $c.data.getMemInfo("userClsCd");
    scwin.sClntNo = $c.data.getMemInfo("clntNo");
    scwin.sClntNm = $c.data.getMemInfo("clntNm");
    scwin.sLobranCd = $c.data.getMemInfo("loUpperLobranCd");


    const codeOptions2 = [ 
        {
            method: "getLuxeComboData", 
            param1: "NcallWorkImplementEBC", 
            param2: "retriveLobran2CodeList",
            param3: ["1"],
            compID: "acb_co_logisticsBranch" 
        }
    ];
    $c.data.setGauceUtil(codeOptions2, scwin.callbackCodeOpt2);



    scwin.params = $c.data.getParameter();
    if (!$c.util.isEmpty(scwin.params["vehclNoCd"])) {
        scwin.vehclNoCd = scwin.params["vehclNoCd"];
    }

    if (!$c.util.isEmpty(scwin.params["vehclNo"])) {
        scwin.vehclNo = scwin.params["vehclNo"];
    }

    if (!$c.util.isEmpty(scwin.params["wrkDt"])) {
        scwin.wrkDt = scwin.params["wrkDt"];
    }

    if (!$c.util.isEmpty(scwin.params["odrNo"])) {
        scwin.odrNo = scwin.params["odrNo"];
    }

    if (!$c.util.isEmpty(scwin.params["wrkLobranCd"])) {
        scwin.wrkLobranCd = scwin.params["wrkLobranCd"];
    }

    //await $c.sbm.execute(sbm_lobran); // 점소 콤보박스 조회

    /*
    // 자가운송사 정보 셋팅
    var GAUCE_DATASET_HEADER = "selfTransClntNo:STRING" // 자가운송사

    ds_condition.SetDataHeader(GAUCE_DATASET_HEADER);
    ds_condition.insertRow();
    */

    acb_co_logisticsBranch.setValue(scwin.sLobranCd);
    ica_wrkDt.focus();


    scwin.f_SetGridColumnMaxLength(gr_emp2);
};

scwin.callbackCodeOpt2 = function () {
    acb_co_logisticsBranch.setValue(scwin.sLobranCd);
}

//-------------------------------------------------------------------------
// 입력 그리드 maxlength 설정
//-------------------------------------------------------------------------
scwin.f_SetGridColumnMaxLength = function (gridViewObj) {
    for (let i = 0; i < gridViewObj.getTotalCol(); i++) {
        let colNm = gridViewObj.getColumnID(i);
        let dataObj = $c.gus.object(gridViewObj.getDataList());
        let colInfo = dataObj.getColumnInfo(colNm);

        if (typeof colInfo != "undefined") {
            gridViewObj.setMaxLength(i, colInfo.length);
        }
    }
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
//        if( scwin.wrkLobranCd != "") {
            if (scwin.sUserClsCd != "01") { //사용자 구분 : 05
                ed_srchSelfTransCoCd.setValue(scwin.sClntNo);
                ed_srchSelfTransCoNm.setValue(scwin.sClntNm);
                $c.gus.cfDisableObjects([ed_srchSelfTransCoCd, ed_srchSelfTransCoNm, btn_srchSelfTransCoCd]);
            } else {
                ed_srchSelfTransCoCd.setValue("");
                ed_srchSelfTransCoNm.setValue("");
                $c.gus.cfEnableObjects([ed_srchSelfTransCoCd, ed_srchSelfTransCoNm, btn_srchSelfTransCoCd]);
            }

            if (scwin.wrkDt != "") {
                ica_wrkDt.setValue(scwin.wrkDt);
                vehclNoCd.setValue(scwin.vehclNoCd);
                vehclNo.setValue(scwin.vehclNo);
                ed_odrNo.setValue(scwin.odrNo);

                scwin.f_Retrieve();
            } else {
                ica_wrkDt.setValue(scwin.strFromDate);
            }
        /*
        } else {

            acb_co_logisticsBranch.setValue(scwin.wrkLobranCd);
            //ica_wrkDt.setValue(scwin.wrkDt);
            ed_odrNo.setValue(scwin.odrNo);
            scwin.f_Retrieve();
        }
        */
        //테스트 데이터
        //ds_retrieve.set("vehclNo", "전남98사7223");
        //ds_retrieve.set("wrkDt", "20060418");
        //ds_retrieve.set("wrkLobranCd", "6AA");
/*
        ds_retrieve.set("vehclNo", "전북82사4614");
        ds_retrieve.set("wrkDt", "20170703");
        ds_retrieve.set("wrkLobranCd", "5BB");
*/        
    }, { "delay": 50 });
};

//-------------------------------------------------------------------------
// TEXT BOX 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUpText = function (inObj, codeObj, disGubun) {
    var pCode = "";
    var pName = "";

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음. //inObj.value.trim() == "" ||
    if (inObj.readOnly || (inObj.getValue() == inObj.hidVal))
        return;

    if (codeObj != null) {
        if (codeObj.tagName == "OBJECT") {
            codeObj.setValue("");
        } else {
            codeObj.setValue("");
            codeObj.hidVal = "";
        }
    }

    pName = inObj.value;

    scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', 'T');
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    scwin.g_chkScroll = false; // 처음부터 RowPositionChanged event를 태우지 않는다.

    if (ed_odrNo.getValue() == "") {
        if (ica_wrkDt.getValue().trim() == "") {
            $c.win.alert("오더번호를 입력하세요");
            return;
        }
        if (ica_wrkDt.getValue().trim() == "" && ed_vehclNo.getValue() == "") {
            $c.win.alert("지시일자와 차량번호를 입력하세요. 지시일자 + 차량번호로 조회해야 합니다");
            return;
        }
		if(ica_wrkDt.getValue().trim() != "" && ed_vehclNo.getValue() == "" && co_lc_transRsltsExistYn.getValue() == "") {
			$c.win.alert("차량번호나 출도착등록여부를  입력하세요.\n지시일자 +차량번호 혹은 지시일자+출도착등록여부로 조회해야 합니다");
			return;
		}
        if (ica_wrkDt.getValue().trim() == "" && ed_vehclNo.getValue() != "") {
            $c.win.alert("지시일자를 입력하세요");
            return;
        }
    } else {
	   // 오더번호가 들어오면 출도착 일시는 무시하고, 오더번호로만 조회한다. 20091028 (박홍준) : 옥민성과장 지시
	   ica_wrkDt.setValue("");
	}

    //ds_retrieve.setEmptyValue();
    //ds_retrieve.set("vehclNo", ed_vehclNo.getValue());
    //ds_retrieve.set("wrkDt", ica_wrkDt.getValue().trim());
    //ds_retrieve.set("odrNo", ed_odrNo.getValue());
    //ds_retrieve.set("ctrtClntNo", ed_ctrtClntNo.getValue().trim());
    //ds_retrieve.set("wrkLobranCd", acb_co_logisticsBranch.getValue());
    //ds_retrieve.set("selfTransClntNo", ed_srchSelfTransCoCd.getValue());
    //ds_retrieve.set("transRsltsExistYn") = co_lc_transRsltsExistYn.BindColVal;
    //ds_retrieve.set("clntMgntNo") = ed_clntMgntNo.Text;
	//ds_retrieve.set("clntMgntList") = result;

    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 코드 조회 팝업
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    var rtnList = new Array();
    var userClntNo = scwin.sClntNo;
    var userClsCd = scwin.sUserClsCd;

    if (disGubun == "1") {
        if (ica_wrkDt.getValue().trim() == "") {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "지시일자"));
            ica_wrkDt.focus();
            return;
        } else {
            if (userClsCd != "01") {
                param = ica_wrkDt.getValue() + "," + userClntNo;
            } else {
                param = ica_wrkDt.getValue();
            }
        }

        udc_vehclNo.cfCommonPopUp(scwin.udc_vehclNo_callBackFunc // 콜백 함수
            , pCode // 화면에서의 ??? Code Element의 Value
            , pName // 화면에서의 ??? Name Element의 Value
            , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
            , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
            , null // Title순서
            , null // 보여주는 각 컬럼들의 폭
            , null // 컬럼중에서 숨기는 컬럼 지정
            , param // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
            , null // POP-UP뛰을때 원도우의 사용자 정의 폭
            , null // POP-UP뛰을때 우도우의 사용자 정의 높이
            , null // 윈도우 위치 Y좌표
            , null // 윈도우 위치 X좌표
            , null // 중복체크여부 ("F")
            , "F" // 전체검색허용여부 ("F")
            , "차량번호,차량단축코드,차량번호" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
    } else if (disGubun == "2") {
        pWhere = ",CTRT";
        // 화주명(계약 거래처코드팝업)
        udc_ctrtClntNo.cfCommonPopUp(scwin.udc_ctrtClntNo_callBackFunc // 콜백 함수
            , pCode // 화면에서의 ??? Code Element의 Value
            , pName // 화면에서의 ??? Name Element의 Value
            , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
            , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
            , null // Title순서
            , null // 보여주는 각 컬럼들의 폭
            , null // 컬럼중에서 숨기는 컬럼 지정
            , pWhere // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
            , null // POP-UP뛰을때 원도우의 사용자 정의 폭
            , null // POP-UP뛰을때 우도우의 사용자 정의 높이
            , null // 윈도우 위치 Y좌표
            , null // 윈도우 위치 X좌표
            , null // 중복체크여부 ("F")
            , pAllSearch // 전체검색허용여부 ("F")
            , "계약 거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );

    } else {
        pWhere = ",LOGISCLNT2";
        // 자가 운송사(거래처코드팝업)
        udc_ctrtClntNo.cfCommonPopUp(scwin.udc_srchSelfTransCoCd_callBackFunc // 콜백 함수
            , pCode // 화면에서의 ??? Code Element의 Value
            , pName // 화면에서의 ??? Name Element의 Value
            , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
            , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
            , null // Title순서
            , null // 보여주는 각 컬럼들의 폭
            , null // 컬럼중에서 숨기는 컬럼 지정
            , pWhere // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
            , null // POP-UP뛰을때 원도우의 사용자 정의 폭
            , null // POP-UP뛰을때 우도우의 사용자 정의 높이
            , null // 윈도우 위치 Y좌표
            , null // 윈도우 위치 X좌표
        );

    }
};

scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    console.log("inObj : "+inObj + "  pairObj : "+ pairObj + "  disGubun : "+ disGubun + "  isCode : "+ isCode);
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)){
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true /*|| isCode == "undefined"*/){
        scwin.f_openPopUp(disGubun, pVal, '', 'T', 'T');
    }
    // inObj가 코드명 필드일 경우 팝업
    else{
        scwin.f_openPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 차량번호 UDC START
scwin.udc_vehclNo_onclickEvent = function (e) {
    scwin.f_openPopUp('1', ed_vehclNoCd.getValue(), ed_vehclNo.getValue(), 'F', 'T');
};

scwin.udc_vehclNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNoCd, ed_vehclNo, '1');
};

scwin.udc_vehclNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNo, ed_vehclNoCd, '1', false);
};

scwin.udc_vehclNo_callBackFunc = function (rtnList) {
    //$c.gus.cfSetReturnValue(ret, ed_vehclNoCd, ed_vehclNo);
    console.log(rtnList);
    if(rtnList != null){
        ed_vehclNoCd.setValue(rtnList[7]);
        ed_vehclNo.setValue(rtnList[0]);
    }
};
// 차량번호 UDC END

// 화주명 UDC START
scwin.udc_ctrtClntNo_onclickEvent = function (e) {
    scwin.f_openPopUp('2', ed_ctrtClntNo.getValue(), ed_ctrtClntNm.getValue(), 'F', 'F');
};

scwin.udc_ctrtClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_ctrtClntNo, ed_ctrtClntNm, '2');
};

scwin.udc_ctrtClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_ctrtClntNm, ed_ctrtClntNo, '2', false);
};

scwin.udc_ctrtClntNo_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_ctrtClntNo, ed_ctrtClntNm);
};
// 화주명 UDC END

// 자가 운송사 UDC START
scwin.udc_srchSelfTransCoCd_onclickEvent = async function (e) {
    scwin.f_openPopUp('3', ed_srchSelfTransCoCd.getValue(), ed_srchSelfTransCoNm.getValue(), 'F', '')
};

scwin.udc_srchSelfTransCoCd_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_srchSelfTransCoCd, ed_srchSelfTransCoNm, '3');
};

scwin.udc_srchSelfTransCoCd_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_srchSelfTransCoNm, ed_srchSelfTransCoCd, '3', false);
};

scwin.udc_srchSelfTransCoCd_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_srchSelfTransCoCd, ed_srchSelfTransCoNm);
};
// 자가 운송사 UDC END

scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList = new Array(); // 공통POP-UP -> 요청화면
    var cnt;
    param = "";

    switch (disGubun) {
        case 1:
            // 규격 Popup           
            scwin.f_scdRetrieve();
            break;

        case 2:
            /* ASIS 사용안되는것 같음
            // 자가운송사 Popup retrieveSelfClnt
            pWhere = ",LOGISCLNT2";
            rtnList = cfCommonPopUp('retrieveClntList', pCode, pName, "T", null, null, null, null, pWhere, null, null, null, null);

            if (rtnList != null) {
                //return value Assign
                ed_srchSelfTransCoCd.setValue(rtnList[0]); //자가운송사코드
                ed_srchSelfTransCoNm.setValue(rtnList[1]); //자가운송사명
                scwin.txt_srchSelfTransCoNm = rtnList[1]; //자가운송사명
                scwin.hid_srchSelfTransCoCd = rtnList[0]; //자가운송사코드
            } else {
                ed_srchSelfTransCoCd.setValue(""); //자가운송사코드
                txt_srchSelfTransCoNm.setValue(""); //자가운송사명
                scwin.txt_srchSelfTransCoNm = ""; //자가운송사명
                scwin.hid_srchSelfTransCoCd = ""; //자가운송사코드
            }
            */
            break;

        default:
            break;
    }
};

scwin.f_Save = async function () {
    //변경한 데이터가 있는지 체크한다.
    if (ds_emp2.getModifiedIndex().length == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_001, "Data"));
        return;
    }

    // 출발일시 from ~ to 체크
    for (var i = 0; i < ds_emp2.getRowCount(); i++) {
        var stDtm = ds_emp2.getCellData(i, "dptDt") + ds_emp2.getCellData(i, "dptHh"); //== "" ? "0000" : ds_emp2.getCellData(i, "dptHh"));
        var endDtm = ds_emp2.getCellData(i, "arvDt") + ds_emp2.getCellData(i, "arvHh"); //
        var dptDt = ds_emp2.getCellData(i, "dptDt");
        var dptHh = ds_emp2.getCellData(i, "dptHh");
        var arvDt = ds_emp2.getCellData(i, "arvDt");
        var arvHh = ds_emp2.getCellData(i, "arvHh");

        //삭제시에만 입출고 관리 대상 제외
        if (ds_emp2.getRowStatus(i) == "D") {
            if (ds_emp2.getCellData(i, "ioDptWrkPlCd") == 1) {
                $c.win.alert("입출고 관리 대상이므로 삭제 못합니다.");
                return;
            }
        }

        if (ds_emp2.getCellData(i, "ioArvWrkPlCd") == 0) {
            if (dptHh == "") {
                ds_emp2.setRowPosition(i);
                gr_emp2.setFocusedCell(i, "dptHh", true);
                $c.win.alert("출발시간을 입력하세요");
                return;
            }
        }

        if (dptDt != "" && dptHh != "" && arvDt != "" && arvHh != "") {
            if (!scwin.f_DifferBetweenDate(stDtm, endDtm)) {
                $c.win.alert(i + "번째 데이타에서 시작일자가 종료일자 이전이어야 합니다.");
                return;
            }
        }

        if (dptDt.length > 0 && dptDt.length < 8) {
            $c.win.alert("날짜형식이 올바르지 않습니다.");
            return;
        }
        if (arvDt.length > 0 && arvDt.length < 8) {
            $c.win.alert("날짜형식이 올바르지 않습니다.");
            return;
        }
        if (dptHh.length > 0 && dptHh.length < 4) {
            $c.win.alert("날짜형식이 올바르지 않습니다.");
            return;
        }
        if (arvHh.length > 0 && arvHh.length < 4) {
            $c.win.alert("날짜형식이 올바르지 않습니다.");
            return;
        }
    }

    scwin.isUpdate();

    if (scwin.hourCheck()) {
        if (scwin.hourNullCheck()) {
            let ret = await $c.win.confirm(MSG_CM_CRM_001);

            if (ret) {
                scwin.pos_groupCode = ds_emp.getRowPosition();
