//-------------------------------------------------------------------------
// 출발일시 from ~ to 체크 함수
//-------------------------------------------------------------------------
scwin.f_DifferBetweenDate = function (sDateStr, eDateStr, dateFormat, row) {
    sDateStr = sDateStr.trim();
    eDateStr = eDateStr.trim();

    if (eDateStr == "00" || sDateStr == "00") {
        return true;
    }
    // 종료일자가 시작일자 이후인지 확인
    if (sDateStr >= eDateStr) {
        return false;
    }

    return true;
};

//-------------------------------------------------------------------------
// 일시 포맷 체크
//-------------------------------------------------------------------------

scwin.f_validDate = function (sDateStr, dateFormat, msg ) {
    sDateStr = sDateStr.trim();

    // default 날짜 포맷
    if (dateFormat == null)
        dateFormat = "YYYYMMDD";

    var validator1 = new covDateValidator(dateFormat);

    // 입력된 날짜의 validation 체크

    if (validator1.validate(sDateStr) == false) {
        cfAlertMsg(msg + " 입력이 잘못 되었습니다.");
        return false;
    }

    return true;
}

//-------------------------------------------------------------------------
// 오더완료처리
//-------------------------------------------------------------------------
scwin.odrNoComplete = async function () {
    //변경한 데이터가 있는지 체크한다.
    if (ds_emp2.getModifiedIndex().length == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_WRN_001, "Data"));
        return;
    }

    // 출발일시 from ~ to 체크
    for (var i = 0; i < ds_emp2.getRowCount(); i++) {
        var dptDt = ds_emp2.getOriginalCellData(i, "dptDt");
        var dptHh = ds_emp2.getOriginalCellData(i, "dptHh");
        var arvDt = ds_emp2.getOriginalCellData(i, "arvDt");
        var arvHh = ds_emp2.getOriginalCellData(i, "arvHh");

        if (ds_emp2.getCellData(i, "che") == 1) {
            if (dptDt == "" || dptHh == "" || arvDt == "" || arvHh == "") {
                ds_emp2.setRowPosition(i);
                //ds_emp2.ColSelect = "true";
                //gr_emp2.SetColumn("dptHh");
                gr_emp2.setFocusedCell(i, "dptHh", true);
                $c.win.alert(i + "번째 테이타는 출도착 처리가 되지 않았습니다. \n 먼저 출도착처리를 해주세요");
                return;
            }
        }
    }

    let ret = await $c.win.confirm("오더완료 처리 하시겠습니까?");

    if (ret) {
        scwin.pos_groupCode = ds_emp.getRowPosition();

        $c.sbm.setAction(sbm_saveEmp, "/ncall.ds.op.wrkrslts.transwrkrslts.RegistBulkDepartureArrivalOrderCompleteCMD.do");
        $c.sbm.execute(sbm_saveEmp);
    }
};

