scwin.gr_emp2_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (ds_emp2.getCellData(rowIndex, "dptDt") == "") {
        gr_emp2.setCellReadOnly(rowIndex, "dptHh", true);
        gr_emp2.setCellReadOnly(rowIndex, "arvDt", true);
        gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);
    } else {
        gr_emp2.setCellReadOnly(rowIndex, "dptHh", false);
        gr_emp2.setCellReadOnly(rowIndex, "arvDt", false);
        gr_emp2.setCellReadOnly(rowIndex, "arvHh", false);
    }

    if (ds_emp2.getCellData(rowIndex, "dptHh") == "") {
        gr_emp2.setCellReadOnly(rowIndex, "arvDt", true);
        gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);
    } else {
        gr_emp2.setCellReadOnly(rowIndex, "arvDt", false);
        gr_emp2.setCellReadOnly(rowIndex, "arvHh", false);
    }

    if (ds_emp2.getCellData(rowIndex, "arvDt") == "") {
        gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);
    } else {
        gr_emp2.setCellReadOnly(rowIndex, "arvHh", false);
    }

    if (columnId == "dptDt" || columnId == "dptHh") {
        if (ds_emp2.getCellData(rowIndex, "ioDptWrkPlCd") == 1) {
            gr_emp2.setCellReadOnly(rowIndex, "dptDt", true);
            gr_emp2.setCellReadOnly(rowIndex, "dptHh", true);

            $c.win.alert("입출고 관리 대상이므로 추가 못합니다.");
            return;
        } else {
            gr_emp2.setCellReadOnly(rowIndex, "dptDt", false);
            gr_emp2.setCellReadOnly(rowIndex, "dptHh", false);
            gr_emp2.setCellReadOnly(rowIndex, "arvDt", false);
            gr_emp2.setCellReadOnly(rowIndex, "arvHh", false);
        }
    }

    if (columnId == "arvDt" || columnId == "arvHh") {
        if (ds_emp2.getCellData(rowIndex, "ioArvWrkPlCd") == 1) {
            gr_emp2.setCellReadOnly(rowIndex, "arvDt", true);
            gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);

            $c.win.alert("입출고 관리 대상이므로 추가 못합니다.");
            return;
        } else if (ds_emp2.getCellData(rowIndex, "ioDptWrkPlCd") == 1) {
            if (ds_emp2.getCellData(rowIndex, "dptHh") == "") {
                gr_emp2.setCellReadOnly(rowIndex, "arvDt", true);
                gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);

                $c.win.alert("출발시간이 없으므로 도착시간을 입력할 수 없습니다.");
            }
        }
        else if (ds_emp2.getOriginalCellData(rowIndex, "dptHh") == "") {
            gr_emp2.setCellReadOnly(rowIndex, "arvDt", true);
            gr_emp2.setCellReadOnly(rowIndex, "arvHh", true);

            $c.win.alert("출발처리하고 도착처리 하세요.");
        } else {
            gr_emp2.setCellReadOnly(rowIndex, "arvDt", false);
            gr_emp2.setCellReadOnly(rowIndex, "arvHh", false);
        }
    }
};

scwin.gr_emp2_onafteredit = async function (rowIndex, columnIndex, value) {
    rowEmp = ds_emp.getRowPosition();
    var tot = 0;

    if (rowIndex > -1 && ds_emp2.getRowCount() > rowIndex) {
        if (columnIndex == 13) { //rglWrkWt

            for (i = 0; i <= rowIndex; i++) {
                tot += ds_emp2.getCellData(i, columnIndex);
            }

            if (tot > ds_emp.getCellData(rowEmp, "rglWrkWt")) {
                let ret = await $c.win.confirm("과적입니다. 그래도 계속 하시겠습니까.");

                if (!ret) {
                    ds_emp2.undoRow(rowIndex); //ds_emp2.UndoMarked();
                }
            }
        }
    }

    switch (columnIndex) {
        case 5: //dptDt
        case 6: //dptHh
        case 7: //arvDt
        case 8: //arvHh
            for (j = 0; j < ds_emp2.getRowCount(); j++) {
                if (ds_emp2.getCellData(j, "coshippingNo") == ds_emp2.getCellData(rowIndex, "coshippingNo") && ds_emp2.getCellData(rowIndex, "coshippingNo") != "") {
                    ds_emp2.setCellData(j, columnIndex, ds_emp2.getCellData(rowIndex, columnIndex));
                }
            }
            break;
        default:
            break;
    }
};

