scwin.sbm_retrieve2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    tbx_totalRows2.setValue($c.gus.cfInsertComma(ds_emp2.getRowCount()));

    if (ds_emp2.getRowCount() > 0) {
        ds_emp2.setRowPosition(0);
    }

    var rowCnt = ds_emp2.getRowCount();
    for(var i=0; i < rowCnt; i++) {
        if(ds_emp2.getCellData(i,"repClntNo") == "000012" &&  ds_emp2.getCellData(i,"steelVehclYn") == 1 && ds_emp2.getCellData(i,"realPdaYn") == 0) {
            //gr_emp2.ColumnProp('allocInput', 'ImgCol') = "true";
            //gr_emp2.ColumnProp('allocInput', 'ImgFitStyle')="1";
            //gr_emp2.ColumnProp('allocInput', 'Show') = "true";
            gr_emp2.setColumnVisible("allocInput", true);
        }else {
            //gr_emp2.ColumnProp('allocInput', 'Show') = "false";
            gr_emp2.setColumnVisible("allocInput", false);
        }
    }

    //테스트
    //ds_emp2.setCellData(0, "dptHh", "12345678");
};

scwin.ds_emp_OnLoadCompleted = function () {
    console.log("####ds_emp_OnLoadCompleted");
    if (ds_emp.getRowCount() == 0) {
        ds_emp2.removeAll();
        $c.win.alert(MSG_CM_WRN_002); //조회된 데이터가 없습니다.;
    } else {
        scwin.g_chkScroll = true;
        console.log("scwin.pos_groupCode=" + scwin.pos_groupCode);
        $c.gus.cfGoPrevPosition(gr_emp, scwin.pos_groupCode);
        //ds_emp.setRowPosition(scwin.pos_groupCode);
    }
};
